// ============================================================================
// CSV Parser Library
// ============================================================================

/** Configuration options for the CSV parser */
export interface CSVOptions {
  /** Field delimiter character (default: ",") */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \r, or \n) */
  lineSeparator?: string;
  /** Whether to perform type coercion (default: true) */
  typeCoercion?: boolean;
}

/** Describes a parsing error on a specific row */
export interface CSVError {
  row: number;
  message: string;
}

/** The result object returned by parseCSV */
export interface CSVResult {
  /** Parsed rows as an array of header-keyed objects */
  rows: Record<string, unknown>[];
  /** Column header names */
  headers: string[];
  /** Collected parsing errors (malformed rows, etc.) */
  errors: CSVError[];

  /** Return only rows matching the predicate */
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  /** Sum all numeric values in a column */
  sum(column: string): number;
  /** Average all numeric values in a column */
  average(column: string): number;
  /** Count total rows */
  count(): number;
  /** Group rows by the values of a column */
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

// ============================================================================
// Internal helpers
// ============================================================================

/**
 * Parse a single CSV line (respecting quoted fields) into an array of raw
 * string tokens.  Returns null if the line has an unterminated quote.
 */
function parseLine(
  line: string,
  delimiter: string,
  quote: string
): string[] | null {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead – escaped quote?
        if (i + 1 < line.length && line[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        } else {
          // Closing quote
          inQuotes = false;
          i++;
          continue;
        }
      } else {
        current += ch;
        i++;
      }
    } else {
      if (ch === quote) {
        // Opening quote
        inQuotes = true;
        i++;
      } else if (line.startsWith(delimiter, i)) {
        fields.push(current);
        current = "";
        i += delimiter.length;
      } else {
        current += ch;
        i++;
      }
    }
  }

  // If we're still inside quotes the line is malformed
  if (inQuotes) {
    return null;
  }

  fields.push(current);
  return fields;
}

/**
 * Coerce a raw string value into a JS primitive when possible.
 */
function coerceValue(raw: string): unknown {
  // Null / empty
  if (raw === "" || raw === "null" || raw === "NULL") {
    return null;
  }

  // Boolean (case-insensitive)
  const lower = raw.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – must match the entire string (avoid partial matches)
  // We use a strict regex first to avoid JS's overly-lenient Number()
  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(raw.trim())) {
    const num = Number(raw);
    if (!Number.isNaN(num)) return num;
  }

  return raw;
}

/**
 * Detect the line separator used in the input by examining only the
 * characters that appear *outside* quoted regions.  This avoids being
 * confused by newlines embedded inside quoted fields.
 */
function detectSeparator(input: string, quote: string): string {
  let inQuotes = false;

  for (let i = 0; i < input.length; i++) {
    const ch = input[i];
    if (inQuotes) {
      if (ch === quote) {
        // Escaped quote?
        if (i + 1 < input.length && input[i + 1] === quote) {
          i++; // skip pair
        } else {
          inQuotes = false;
        }
      }
    } else {
      if (ch === quote) {
        inQuotes = true;
      } else if (ch === "\r") {
        if (i + 1 < input.length && input[i + 1] === "\n") {
          return "\r\n";
        }
        return "\r";
      } else if (ch === "\n") {
        return "\n";
      }
    }
  }

  // No line break found outside quotes – default to \n
  return "\n";
}

/**
 * Split the full input into logical lines, respecting quoted fields that
 * may contain embedded newlines.
 */
function splitLines(input: string, lineSeparator: string | undefined, quote: string): string[] {
  const sep = lineSeparator ?? detectSeparator(input, quote);

  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += ch + quote;
          i += 2;
          continue;
        } else {
          inQuotes = false;
          current += ch;
          i++;
          continue;
        }
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        inQuotes = true;
        current += ch;
        i++;
      } else if (input.startsWith(sep, i)) {
        lines.push(current);
        current = "";
        i += sep.length;
      } else {
        current += ch;
        i++;
      }
    }
  }

  // Push last line (may be empty if input ends with separator)
  lines.push(current);

  return lines;
}

// ============================================================================
// Main entry point
// ============================================================================

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const typeCoercion = options?.typeCoercion ?? true;

  const errors: CSVError[] = [];
  const rows: Record<string, unknown>[] = [];

  // Edge case: completely empty / whitespace-only input
  if (input.trim().length === 0) {
    return buildResult([], [], errors);
  }

  const lines = splitLines(input, lineSeparator, quote);

  // Strip trailing empty line produced by a final newline
  if (lines.length > 0 && lines[lines.length - 1].trim() === "") {
    lines.pop();
  }

  if (lines.length === 0) {
    return buildResult([], [], errors);
  }

  // ---- Parse header row ----
  const headerFields = parseLine(lines[0], delimiter, quote);
  if (headerFields === null) {
    errors.push({ row: 1, message: "Malformed header row: unterminated quote" });
    return buildResult([], [], errors);
  }
  const headers = headerFields.map((h) => h.trim());

  // ---- Parse data rows ----
  for (let r = 1; r < lines.length; r++) {
    const line = lines[r];

    // Skip completely blank lines
    if (line.trim() === "") continue;

    const fields = parseLine(line, delimiter, quote);

    if (fields === null) {
      errors.push({
        row: r + 1, // 1-based
        message: "Malformed row: unterminated quote",
      });
      continue;
    }

    if (fields.length !== headers.length) {
      errors.push({
        row: r + 1,
        message: `Column count mismatch: expected ${headers.length} but got ${fields.length}`,
      });
    }

    const obj: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c++) {
      const raw = c < fields.length ? fields[c] : "";
      obj[headers[c]] = typeCoercion ? coerceValue(raw) : raw;
    }
    rows.push(obj);
  }

  return buildResult(headers, rows, errors);
}

// ============================================================================
// Build the rich result object with helper methods
// ============================================================================

function buildResult(
  headers: string[],
  rows: Record<string, unknown>[],
  errors: CSVError[]
): CSVResult {
  return {
    headers,
    rows,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean) {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

