// Uses plain assertions (throws on failure). No test framework required.

import { parseCSV, CSVResult } from "./csv-parser";

// ---- tiny test harness ----
let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) throw new Error(`Assertion failed: ${message}`);
}

function assertStrictEqual(actual: unknown, expected: unknown, label: string) {
  if (actual !== expected) {
    throw new Error(
      `${label}: expected ${JSON.stringify(expected)} but got ${JSON.stringify(actual)}`
    );
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, label: string) {
  const a = JSON.stringify(actual);
  const b = JSON.stringify(expected);
  if (a !== b) {
    throw new Error(`${label}:\n  expected: ${b}\n  actual:   ${a}`);
  }
}

function test(name: string, fn: () => void) {
  try {
    fn();
    passed++;
    console.log(`  ✅ ${name}`);
  } catch (e: any) {
    failed++;
    const msg = `  ❌ ${name} — ${e.message}`;
    failures.push(msg);
    console.log(msg);
  }
}

function section(title: string) {
  console.log(`\n━━━ ${title} ━━━`);
}

// ============================================================================
// Tests
// ============================================================================

// ---- 1. Basic Parsing ----
section("Basic Parsing");

test("parses simple CSV into array of objects", () => {
  const csv = "name,age,city\nAlice,30,NYC\nBob,25,LA";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertDeepEqual(result.headers, ["name", "age", "city"], "headers");
  assertStrictEqual(result.rows[0]["name"], "Alice", "first row name");
  assertStrictEqual(result.rows[0]["age"], 30, "first row age (number)");
  assertStrictEqual(result.rows[0]["city"], "NYC", "first row city");
  assertStrictEqual(result.rows[1]["name"], "Bob", "second row name");
  assertStrictEqual(result.rows[1]["age"], 25, "second row age");
});

test("handles trailing newline without creating extra row", () => {
  const csv = "a,b\n1,2\n";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "row count");
});

test("handles \\r\\n line endings", () => {
  const csv = "x,y\r\n1,2\r\n3,4\r\n";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertStrictEqual(result.rows[0]["x"], 1, "first row x");
  assertStrictEqual(result.rows[1]["y"], 4, "second row y");
});

test("handles \\r line endings", () => {
  const csv = "x,y\r1,2\r3,4";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
});

// ---- 2. Quoted Fields ----
section("Quoted Fields");

test("parses quoted fields containing commas", () => {
  const csv = 'name,address\nAlice,"123 Main St, Apt 4"\nBob,"456 Oak Ave, Suite 7"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["address"], "123 Main St, Apt 4", "address with comma");
  assertStrictEqual(result.rows[1]["address"], "456 Oak Ave, Suite 7", "address with comma 2");
});

test("parses quoted field at start of line", () => {
  const csv = '"name",age\n"Alice",30';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["name"], "Alice", "quoted name");
});

test("parses quoted fields containing newlines", () => {
  const csv = 'name,bio\nAlice,"Line1\nLine2"\nBob,simple';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "row count");
  assertStrictEqual(result.rows[0]["bio"], "Line1\nLine2", "field with embedded newline");
  assertStrictEqual(result.rows[1]["bio"], "simple", "normal field after multiline");
});

test("handles empty quoted fields", () => {
  const csv = 'a,b\n"",""';
  const result = parseCSV(csv);
  // Empty quoted field → coerced to null (empty string)
  assertStrictEqual(result.rows[0]["a"], null, "empty quoted = null");
  assertStrictEqual(result.rows[0]["b"], null, "empty quoted = null");
});

// ---- 3. Escaped Quotes ----
section("Escaped Quotes");

test("handles escaped double quotes inside quoted field", () => {
  const csv = 'name,quote\nAlice,"She said ""hello"""\nBob,"He said ""bye"""';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["quote"], 'She said "hello"', "escaped quotes");
  assertStrictEqual(result.rows[1]["quote"], 'He said "bye"', "escaped quotes 2");
});

test("handles field that is only escaped quotes", () => {
  const csv = 'a\n""""""';
  // """""" -> three pairs inside outer quotes = literal ""
  // Actually: outer quotes consume first & last ", remaining """" = two escaped = ""
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["a"], '""', 'double-escaped quotes');
});

test("handles single escaped quote inside field", () => {
  const csv = 'a\n""""';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["a"], '"', "single escaped quote");
});

// ---- 4. Custom Delimiters ----
section("Custom Delimiters");

test("supports tab delimiter", () => {
  const csv = "name\tage\nAlice\t30\nBob\t25";
  const result = parseCSV(csv, { delimiter: "\t" });
  assertStrictEqual(result.headers.length, 2, "header count");
  assertStrictEqual(result.rows[0]["name"], "Alice", "tab-delimited name");
  assertStrictEqual(result.rows[0]["age"], 30, "tab-delimited age");
});

test("supports semicolon delimiter", () => {
  const csv = "a;b;c\n1;2;3";
  const result = parseCSV(csv, { delimiter: ";" });
  assertDeepEqual(result.headers, ["a", "b", "c"], "semicolon headers");
  assertStrictEqual(result.rows[0]["b"], 2, "semicolon value");
});

test("supports pipe delimiter", () => {
  const csv = "a|b\n1|2";
  const result = parseCSV(csv, { delimiter: "|" });
  assertStrictEqual(result.rows[0]["a"], 1, "pipe value a");
  assertStrictEqual(result.rows[0]["b"], 2, "pipe value b");
});

test("supports custom quote character (single quote)", () => {
  const csv = "name,val\n'hello, world',42";
  const result = parseCSV(csv, { quote: "'" });
  assertStrictEqual(result.rows[0]["name"], "hello, world", "single-quote wrapped");
});

test("supports custom line separator", () => {
  const csv = "a,b|1,2|3,4";
  const result = parseCSV(csv, { lineSeparator: "|" });
  assertStrictEqual(result.rows.length, 2, "custom line sep row count");
  assertStrictEqual(result.rows[1]["a"], 3, "custom line sep value");
});

// ---- 5. Type Coercion ----
section("Type Coercion");

test("coerces integers", () => {
  const csv = "v\n0\n42\n-7\n1000000";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["v"], 0, "zero");
  assertStrictEqual(result.rows[1]["v"], 42, "positive int");
  assertStrictEqual(result.rows[2]["v"], -7, "negative int");
  assertStrictEqual(result.rows[3]["v"], 1000000, "large int");
});

test("coerces floats", () => {
  const csv = "v\n3.14\n-0.5\n.25\n1e3\n2.5e-1";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["v"], 3.14, "pi-ish");
  assertStrictEqual(result.rows[1]["v"], -0.5, "negative float");
  assertStrictEqual(result.rows[2]["v"], 0.25, "leading dot");
  assertStrictEqual(result.rows[3]["v"], 1000, "scientific notation");
  assertStrictEqual(result.rows[4]["v"], 0.25, "scientific notation neg exp");
});

test("coerces booleans (case-insensitive)", () => {
  const csv = "v\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["v"], true, "true");
  assertStrictEqual(result.rows[1]["v"], false, "false");
  assertStrictEqual(result.rows[2]["v"], true, "TRUE");
  assertStrictEqual(result.rows[3]["v"], false, "FALSE");
  assertStrictEqual(result.rows[4]["v"], true, "True");
  assertStrictEqual(result.rows[5]["v"], false, "False");
});

test("coerces null values", () => {
  const csv = "a,b,c\nnull,NULL,";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["a"], null, "null");
  assertStrictEqual(result.rows[0]["b"], null, "NULL");
  assertStrictEqual(result.rows[0]["c"], null, "empty string → null");
});

test("leaves plain strings as strings", () => {
  const csv = "v\nhello\nworld\n123abc\ntrue1";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["v"], "hello", "plain string");
  assertStrictEqual(result.rows[1]["v"], "world", "plain string");
  assertStrictEqual(result.rows[2]["v"], "123abc", "not a number");
  assertStrictEqual(result.rows[3]["v"], "true1", "not a boolean");
});

test("type coercion can be disabled", () => {
  const csv = "v\n42\ntrue\nnull";
  const result = parseCSV(csv, { typeCoercion: false });
  assertStrictEqual(result.rows[0]["v"], "42", "number stays string");
  assertStrictEqual(result.rows[1]["v"], "true", "bool stays string");
  assertStrictEqual(result.rows[2]["v"], "null", "null stays string");
});

// ---- 6. Error Handling ----
section("Error Handling");

test("collects error for row with too few columns", () => {
  const csv = "a,b,c\n1,2\n4,5,6";
  const result = parseCSV(csv);
  assertStrictEqual(result.errors.length, 1, "one error");
  assertStrictEqual(result.errors[0].row, 2, "error on row 2");
  assert(result.errors[0].message.includes("mismatch"), "message mentions mismatch");
  // Row is still partially included
  assertStrictEqual(result.rows.length, 2, "both rows still present");
});

test("collects error for row with too many columns", () => {
  const csv = "a,b\n1,2,3\n4,5";
  const result = parseCSV(csv);
  assertStrictEqual(result.errors.length, 1, "one error");
  assertStrictEqual(result.errors[0].row, 2, "error row");
});

test("collects error for unterminated quote", () => {
  const csv = 'a,b\n"hello,world\n1,2';
  const result = parseCSV(csv);
  assert(result.errors.length >= 1, "at least one error");
  assert(
    result.errors.some((e) => e.message.toLowerCase().includes("unterminated")),
    "mentions unterminated quote"
  );
});

test("multiple errors are all collected", () => {
  const csv = "a,b\n1\n2\n3,4,5";
  const result = parseCSV(csv);
  assertStrictEqual(result.errors.length, 3, "three errors");
  // Row numbers should be 2, 3, 4
  assertStrictEqual(result.errors[0].row, 2, "first error row");
  assertStrictEqual(result.errors[1].row, 3, "second error row");
  assertStrictEqual(result.errors[2].row, 4, "third error row");
});

test("parser does not crash on malformed input", () => {
  // Throw a bunch of junk at it
  const weird = '"""","""\na"""""",b\n",",';
  let threw = false;
  try {
    parseCSV(weird);
  } catch {
    threw = true;
  }
  assert(!threw, "parser should never throw");
});

// ---- 7. Filter ----
section("Filter");

test("filter returns matching rows", () => {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv);
  const over28 = result.filter((r) => (r["age"] as number) > 28);
  assertStrictEqual(over28.length, 2, "two matches");
  assertStrictEqual(over28[0]["name"], "Alice", "Alice");
  assertStrictEqual(over28[1]["name"], "Charlie", "Charlie");
});

test("filter returns empty array when nothing matches", () => {
  const csv = "v\n1\n2\n3";
  const result = parseCSV(csv);
  const none = result.filter(() => false);
  assertStrictEqual(none.length, 0, "no matches");
});

test("filter with string predicate", () => {
  const csv = "fruit,qty\napple,5\nbanana,3\napricot,8";
  const result = parseCSV(csv);
  const aFruits = result.filter((r) => (r["fruit"] as string).startsWith("a"));
  assertStrictEqual(aFruits.length, 2, "two a-fruits");
});

// ---- 8. Aggregation Methods ----
section("Aggregation – sum");

test("sum of numeric column", () => {
  const csv = "item,price\nA,10\nB,20\nC,30";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("price"), 60, "sum = 60");
});

test("sum ignores non-numeric values", () => {
  const csv = "v\n10\nhello\n20\nnull";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("v"), 30, "sum skips non-numbers");
});

test("sum of non-existent column is 0", () => {
  const csv = "a\n1";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("zzz"), 0, "sum of missing col");
});

test("sum with negative numbers", () => {
  const csv = "v\n10\n-3\n-7";
  const result = parseCSV(csv);
  assertStrictEqual(result.sum("v"), 0, "sum with negatives");
});

section("Aggregation – average");

test("average of numeric column", () => {
  const csv = "v\n10\n20\n30";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("v"), 20, "average = 20");
});

test("average ignores non-numeric values", () => {
  const csv = "v\n10\nhello\n20";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("v"), 15, "average of 10,20");
});

test("average of empty/non-numeric column returns 0", () => {
  const csv = "v\nhello\nworld";
  const result = parseCSV(csv);
  assertStrictEqual(result.average("v"), 0, "average when no numbers");
});

section("Aggregation – count");

test("count returns number of rows", () => {
  const csv = "a\n1\n2\n3\n4\n5";
  const result = parseCSV(csv);
  assertStrictEqual(result.count(), 5, "count = 5");
});

test("count on header-only CSV is 0", () => {
  const csv = "a,b,c";
  const result = parseCSV(csv);
  assertStrictEqual(result.count(), 0, "count = 0");
});

section("Aggregation – groupBy");

test("groupBy groups rows by column value", () => {
  const csv = "dept,name\nEng,Alice\nSales,Bob\nEng,Charlie\nSales,Diana\nEng,Eve";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");
  assertStrictEqual(groups.size, 2, "two groups");
  assertStrictEqual(groups.get("Eng")!.length, 3, "3 in Eng");
  assertStrictEqual(groups.get("Sales")!.length, 2, "2 in Sales");
});

test("groupBy with numeric keys", () => {
  const csv = "score,name\n100,Alice\n90,Bob\n100,Charlie";
  const result = parseCSV(csv);
  const groups = result.groupBy("score");
  assertStrictEqual(groups.get(100)!.length, 2, "two with 100");
  assertStrictEqual(groups.get(90)!.length, 1, "one with 90");
});

test("groupBy with null values", () => {
  const csv = "a,b\n1,x\n,y\n,z";
  const result = parseCSV(csv);
  const groups = result.groupBy("a");
  assertStrictEqual(groups.get(null)!.length, 2, "two nulls grouped");
});

// ---- 9. Edge Cases ----
section("Edge Cases");

test("empty input returns empty result", () => {
  const result = parseCSV("");
  assertStrictEqual(result.rows.length, 0, "no rows");
  assertStrictEqual(result.headers.length, 0, "no headers");
  assertStrictEqual(result.errors.length, 0, "no errors");
  assertStrictEqual(result.count(), 0, "count = 0");
});

test("whitespace-only input returns empty result", () => {
  const result = parseCSV("   \n  \n  ");
  assertStrictEqual(result.rows.length, 0, "no rows");
});

test("single column CSV", () => {
  const csv = "id\n1\n2\n3";
  const result = parseCSV(csv);
  assertStrictEqual(result.headers.length, 1, "one header");
  assertStrictEqual(result.rows.length, 3, "three rows");
  assertStrictEqual(result.rows[2]["id"], 3, "value correct");
});

test("single row (header only + one data row)", () => {
  const csv = "a,b\n1,2";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "one row");
});

test("header only, no data rows", () => {
  const csv = "a,b,c\n";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 0, "no data rows");
  assertDeepEqual(result.headers, ["a", "b", "c"], "headers present");
});

test("very large field", () => {
  const bigValue = "x".repeat(100_000);
  const csv = `a\n${bigValue}`;
  const result = parseCSV(csv);
  assertStrictEqual((result.rows[0]["a"] as string).length, 100_000, "large field preserved");
});

test("many columns", () => {
  const n = 500;
  const headers = Array.from({ length: n }, (_, i) => `col${i}`).join(",");
  const values = Array.from({ length: n }, (_, i) => String(i)).join(",");
  const csv = `${headers}\n${values}`;
  const result = parseCSV(csv);
  assertStrictEqual(result.headers.length, n, "500 headers");
  assertStrictEqual(result.rows[0]["col0"], 0, "first col");
  assertStrictEqual(result.rows[0]["col499"], 499, "last col");
});

test("many rows", () => {
  const lines = ["v"];
  for (let i = 0; i < 10_000; i++) lines.push(String(i));
  const csv = lines.join("\n");
  const result = parseCSV(csv);
  assertStrictEqual(result.count(), 10_000, "10k rows");
  assertStrictEqual(result.sum("v"), (9999 * 10000) / 2, "sum of 0..9999");
});

test("fields with leading/trailing whitespace preserved (not headers)", () => {
  // Headers are trimmed, but field values are not automatically trimmed
  // (They go through coercion which doesn't trim for strings)
  const csv = "a, b \n hello , world ";
  const result = parseCSV(csv);
  assertDeepEqual(result.headers, ["a", "b"], "headers trimmed");
  // Values: " hello " and " world " — these are kept as strings
  assertStrictEqual(result.rows[0]["a"], " hello ", "value not trimmed");
});

test("quoted field that looks like a number stays as coerced value", () => {
  // Even quoted, "42" after quote-stripping becomes "42" and gets coerced
  const csv = 'v\n"42"';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["v"], 42, "quoted number is coerced");
});

test("completely empty rows are skipped", () => {
  const csv = "a,b\n1,2\n\n3,4\n\n";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 2, "blank lines skipped");
  assertStrictEqual(result.errors.length, 0, "no errors for blank lines");
});

test("commas inside quoted field with custom delimiter still work", () => {
  const csv = 'a;b\n"hello, world";42';
  const result = parseCSV(csv, { delimiter: ";" });
  assertStrictEqual(result.rows[0]["a"], "hello, world", "comma in field with ; delimiter");
  assertStrictEqual(result.rows[0]["b"], 42, "second field");
});

test("chaining filter with aggregation on filtered subset", () => {
  const csv = "dept,salary\nEng,100\nSales,80\nEng,120\nSales,90";
  const result = parseCSV(csv);
  const engRows = result.filter((r) => r["dept"] === "Eng");
  // Manual sum over filtered rows
  const engTotal = engRows.reduce((s, r) => s + (r["salary"] as number), 0);
  assertStrictEqual(engTotal, 220, "filtered sum");
});

test("groupBy then aggregate per group", () => {
  const csv = "dept,salary\nEng,100\nSales,80\nEng,120\nSales,90\nEng,110";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  const engAvg =
    groups.get("Eng")!.reduce((s, r) => s + (r["salary"] as number), 0) /
    groups.get("Eng")!.length;
  assertStrictEqual(engAvg, 110, "Eng average salary");

  const salesAvg =
    groups.get("Sales")!.reduce((s, r) => s + (r["salary"] as number), 0) /
    groups.get("Sales")!.length;
  assertStrictEqual(salesAvg, 85, "Sales average salary");
});

test("multiline field with \\r\\n inside quotes", () => {
  const csv = 'a,b\n"line1\r\nline2",42';
  const result = parseCSV(csv);
  assertStrictEqual(result.rows.length, 1, "one row");
  assertStrictEqual(result.rows[0]["a"], "line1\r\nline2", "multiline field preserved");
  assertStrictEqual(result.rows[0]["b"], 42, "second field correct");
});

test("boolean coercion does not apply to mixed case like tRuE beyond case insensitivity", () => {
  const csv = "v\ntRuE\nfAlSe";
  const result = parseCSV(csv);
  assertStrictEqual(result.rows[0]["v"], true, "tRuE → true");
  assertStrictEqual(result.rows[1]["v"], false, "fAlSe → false");
